#include <iostream>
#include <stack>
#include <string>

class Solution {
public:
    bool validateStackSequences(std::string s) {
        std::stack<char> st;
        int i = 0, j = s.length() - 1;
        while (i <= j) {
            if (s[i] == '(' || s[i] == '{' || s[i] == '[') st.push(s[i]);
            else if (s[i] == ')' || s[i] == '}' || s[i] == ']') {
                if (st.empty()) return false;
                char c = st.top();
                st.pop();
                if (s[i] == ')' && c == '(') {} else if (s[i] == '}' && c == '{') {} else if (s[i] == ']' && c == '[') {}
                else return false;
            }
            i++;
        }
        return st.empty();
    }
};

int main() {
    std::string s;
    while (std::getline(std::cin, s)) {
        if (Solution().validateStackSequences(s)) std::cout << 'True' << std::endl;
        else std::cout << 'False' << std::endl;
    }
    return 0;
}
